            ))}
          </div>
        </div>

        <div className="flex-1 flex flex-col min-w-0">
          <div className="border-b border-white/5 px-6 py-3 flex items-center gap-4 bg-navy-2 flex-shrink-0">
            <button onClick={() => setView("list")} className="text-white/40 hover:text-white transition-all">
              <i className="ti ti-arrow-left text-lg" />
            </button>
            <input
              value={formName}
              onChange={(e) => setFormName(e.target.value)}
              className="bg-transparent text-white font-bold text-base outline-none border-b border-transparent hover:border-white/20 focus:border-cl-accent transition-all"
            />
            <div className="ml-auto flex gap-2">
              <button
                onClick={() => { setPreviewForm({ id: "new", name: formName, description: "", fields, responses: 0, status: "draft", createdAt: "Ahora" }); setView("preview"); }}
                className="flex items-center gap-2 text-sm text-white/60 hover:text-white bg-white/5 hover:bg-white/10 px-4 py-2 rounded-lg transition-all"
              >
                <i className="ti ti-eye" /> Vista previa
              </button>
              <button
                onClick={() => setView("list")}
                className="flex items-center gap-2 text-sm bg-cl-accent text-navy font-bold px-4 py-2 rounded-lg hover:bg-cl-accent/90 transition-all"
              >
                <i className="ti ti-cloud-upload" /> Publicar
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto p-6">
            {fields.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-64 text-white/20">
                <i className="ti ti-forms text-5xl mb-3" />
                <p className="text-sm">Agregá campos desde el panel izquierdo</p>
              </div>
            ) : (
              <div className="max-w-2xl mx-auto space-y-3">
                {fields.map((field, idx) => (
                  <div
                    key={field.id}
                    className={`bg-navy-2 border rounded-xl p-4 transition-all ${draggingIdx === idx ? "border-cl-accent/40 opacity-60" : "border-white/10 hover:border-white/20"}`}
                    draggable
                    onDragStart={() => setDraggingIdx(idx)}
                    onDragEnd={() => setDraggingIdx(null)}
                  >
                    <div className="flex items-center gap-3 mb-3">
                      <i className="ti ti-grip-vertical text-white/20 cursor-grab" />
                      <input
