          className="border-2 border-dashed border-white/10 hover:border-cl-accent/30 rounded-xl p-5 flex flex-col items-center justify-center gap-3 text-white/30 hover:text-cl-accent transition-all min-h-[200px]"
        >
          <i className="ti ti-plus text-3xl" />
          <span className="text-sm font-semibold">Nuevo formulario</span>
        </button>
      </div>

      <div className="mt-8 bg-navy-2 border border-white/10 rounded-xl p-5">
