        <div className="bg-black/30 rounded-lg p-3 font-mono text-xs text-cl-accent/80 select-all">
          {'<script src="https://clientum.com.ar/embed.js" data-form-id="TU_ID"></script>'}
        </div>
      </div>
    </div>
  );
}

