function getInitials(name: string) {
  return name.split(" ").map(w => w[0]).slice(0, 2).join("").toUpperCase();
}

type Tab = "pipeline" | "contactos" | "empresas" | "actividades";

export default function CRMPage() {
  const [tab, setTab] = useState<Tab>("pipeline");
  const [search, setSearch] = useState("");
  const [selectedDeal, setSelectedDeal] = useState<Deal | null>(null);

  const tabs: { id: Tab; label: string; icon: string }[] = [
    { id: "pipeline", label: "Pipeline", icon: "ti-layout-kanban" },
    { id: "contactos", label: "Contactos", icon: "ti-users" },
    { id: "empresas", label: "Empresas", icon: "ti-building" },
    { id: "actividades", label: "Actividades", icon: "ti-activity" },
  ];

  const pipelineValue = DEMO_DEALS.filter(d => d.stage !== "cerrado_ganado" && d.stage !== "cerrado_perdido").reduce((s, d) => s + d.value, 0);
  const wonValue = DEMO_DEALS.filter(d => d.stage === "cerrado_ganado").reduce((s, d) => s + d.value, 0);
  const weightedValue = DEMO_DEALS.reduce((s, d) => s + d.value * d.probability / 100, 0);

  return (
    <div className="flex flex-col h-full">
      <div className="border-b border-white/5 px-6 py-3 flex items-center gap-2 bg-navy-2 flex-shrink-0">
        {tabs.map(t => (
          <button key={t.id} onClick={() => setTab(t.id)}
            className={`flex items-center gap-2 px-4 py-1.5 text-sm font-semibold rounded-lg transition-all ${tab === t.id ? "bg-cl-accent/10 text-cl-accent" : "text-white/50 hover:text-white"}`}>
            <i className={`ti ${t.icon} text-base`} />{t.label}
          </button>
        ))}
        <div className="ml-auto flex items-center gap-2">
          <div className="flex items-center gap-2 bg-white/5 border border-white/10 rounded-lg px-3 py-1.5">
            <i className="ti ti-search text-sm text-white/30" />
            <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Buscar..." className="bg-transparent text-sm text-white outline-none w-36 placeholder-white/30" />
          </div>
          <button className="flex items-center gap-2 text-sm bg-cl-accent text-navy font-bold px-4 py-1.5 rounded-lg hover:bg-cl-accent/90 transition-all">
            <i className="ti ti-plus" /> Nuevo
          </button>
        </div>
      </div>

      {tab === "pipeline" && (
        <div className="flex flex-col flex-1 min-h-0">
          <div className="grid grid-cols-3 gap-4 px-6 py-4 border-b border-white/5 flex-shrink-0">
            {[
              { label: "Pipeline total", value: `$${(pipelineValue / 1000).toFixed(0)}K`, sub: `${DEMO_DEALS.filter(d => d.stage !== "cerrado_ganado").length} oportunidades activas`, icon: "ti-chart-area-line", color: "text-blue-400", bg: "bg-blue-400/10" },
              { label: "Ponderado", value: `$${(weightedValue / 1000).toFixed(0)}K`, sub: "Ajustado por probabilidad", icon: "ti-percentage", color: "text-yellow-400", bg: "bg-yellow-400/10" },
              { label: "Ganado este mes", value: `$${(wonValue / 1000).toFixed(0)}K`, sub: `${DEMO_DEALS.filter(d => d.stage === "cerrado_ganado").length} deals cerrados`, icon: "ti-trophy", color: "text-cl-accent", bg: "bg-cl-accent/10" },
            ].map(s => (
              <div key={s.label} className="bg-navy-2 border border-white/10 rounded-xl p-4 flex items-center gap-3">
                <div className={`w-10 h-10 ${s.bg} rounded-lg flex items-center justify-center flex-shrink-0`}>
                  <i className={`ti ${s.icon} text-xl ${s.color}`} />
                </div>
                <div>
                  <p className="text-xl font-bold text-white">{s.value}</p>
                  <p className="text-xs text-white/40">{s.label}</p>
                  <p className="text-[10px] text-white/25">{s.sub}</p>
                </div>
              </div>
            ))}
          </div>

          <div className="flex-1 overflow-x-auto overflow-y-hidden">
            <div className="flex gap-4 p-6 h-full" style={{ minWidth: `${STAGES.length * 260}px` }}>
              {STAGES.map(stage => {
                const deals = DEMO_DEALS.filter(d => d.stage === stage.id);
