              return (
                <div key={status}>
                  <div className="sticky top-0 bg-navy-card2 px-6 py-2 flex items-center gap-2 border-b border-white/5 z-10">
                    <i className={`ti ${s.icon} text-sm ${s.color}`} />
                    <span className={`text-xs font-bold ${s.color}`}>{s.label}</span>
                    <span className="text-xs text-white/20">{issues.length}</span>
                  </div>
                  {issues.map(issue => (
                    <div key={issue.id} onClick={() => setSelectedIssue(issue)}
                      className="px-6 py-3 flex items-center gap-4 border-b border-white/5 hover:bg-white/2 cursor-pointer group transition-colors">
                      <i className={`ti ${STATUSES[issue.status].icon} text-base ${STATUSES[issue.status].color} flex-shrink-0`} />
                      <i className={`ti ${PRIORITIES[issue.priority].icon} text-sm ${PRIORITIES[issue.priority].color} flex-shrink-0`} />
                      <span className="text-[10px] text-white/25 font-mono flex-shrink-0 w-14">{issue.code}</span>
                      <span className="text-sm text-white/80 flex-1 min-w-0 truncate group-hover:text-white transition-colors">{issue.title}</span>
                      <div className="flex items-center gap-2 flex-shrink-0">
                        {issue.labels.map(l => (
                          <span key={l} className={`text-[10px] font-semibold px-1.5 py-0.5 rounded ${LABEL_COLORS[l] ?? "bg-white/10 text-white/40"}`}>{l}</span>
                        ))}
                        {issue.sprint && <span className="text-[10px] text-white/20 hidden lg:block">{issue.sprint}</span>}
                        {issue.dueDate && <span className="text-[10px] text-white/25 hidden lg:flex items-center gap-1"><i className="ti ti-calendar text-xs" />{issue.dueDate}</span>}
                        <div className={`w-6 h-6 ${issue.assigneeColor} rounded-full flex items-center justify-center text-[9px] font-bold text-white`}>
                          {issue.assignee}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              );
            })}
          </div>
        )}

        {view === "kanban" && (
          <div className="flex-1 overflow-x-auto overflow-y-hidden">
            <div className="flex gap-4 p-6 h-full" style={{ minWidth: `${5 * 240}px` }}>
              {(["por_hacer", "en_progreso", "en_revision", "completado", "backlog"] as IssueStatus[]).map(status => {
                const issues = filteredIssues.filter(i => i.status === status);
                const s = STATUSES[status];
                return (
                  <div key={status} className="flex flex-col w-56 flex-shrink-0">
                    <div className="flex items-center gap-2 mb-3">
                      <i className={`ti ${s.icon} text-sm ${s.color}`} />
                      <span className={`text-xs font-bold ${s.color}`}>{s.label}</span>
                      <span className="ml-auto w-5 h-5 rounded-full bg-white/10 flex items-center justify-center text-[10px] text-white/40 font-bold">{issues.length}</span>
                    </div>
                    <div className="flex-1 space-y-2 overflow-y-auto">
                      {issues.map(issue => (
                        <div key={issue.id} onClick={() => setSelectedIssue(issue)}
                          className="bg-navy-2 border border-white/10 hover:border-cl-accent/30 rounded-xl p-3 cursor-pointer transition-all">
                          <div className="flex items-start justify-between gap-2 mb-2">
                            <p className="text-xs font-bold text-white leading-tight">{issue.title}</p>
                            <i className={`ti ${PRIORITIES[issue.priority].icon} text-sm ${PRIORITIES[issue.priority].color} flex-shrink-0 mt-0.5`} />
                          </div>
                          <div className="flex items-center justify-between">
                            <span className="text-[10px] text-white/25 font-mono">{issue.code}</span>
                            <div className={`w-5 h-5 ${issue.assigneeColor} rounded-full flex items-center justify-center text-[9px] font-bold text-white`}>
                              {issue.assignee}
                            </div>
                          </div>
                          {issue.labels.length > 0 && (
                            <div className="flex flex-wrap gap-1 mt-2">
                              {issue.labels.map(l => (
                                <span key={l} className={`text-[9px] font-semibold px-1 py-0.5 rounded ${LABEL_COLORS[l] ?? "bg-white/10 text-white/40"}`}>{l}</span>
                              ))}
                            </div>
                          )}
                        </div>
                      ))}
                      <button className="w-full border border-dashed border-white/10 hover:border-cl-accent/20 rounded-xl py-2 text-xs text-white/20 hover:text-cl-accent/50 transition-all">
                        + Agregar
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>

      {selectedIssue && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4" onClick={() => setSelectedIssue(null)}>
          <div className="bg-navy-2 border border-white/10 rounded-2xl p-6 w-full max-w-lg" onClick={e => e.stopPropagation()}>
            <div className="flex items-center gap-2 mb-4">
              <span className="text-xs font-mono text-white/30">{selectedIssue.code}</span>
              <button onClick={() => setSelectedIssue(null)} className="ml-auto text-white/30 hover:text-white transition-all"><i className="ti ti-x" /></button>
            </div>
            <h3 className="font-bold text-white text-lg mb-2">{selectedIssue.title}</h3>
            <p className="text-sm text-white/50 mb-5">{selectedIssue.description}</p>
            <div className="grid grid-cols-2 gap-3 mb-5">
              {[
                { label: "Estado", value: STATUSES[selectedIssue.status].label, icon: STATUSES[selectedIssue.status].icon, color: STATUSES[selectedIssue.status].color },
                { label: "Prioridad", value: PRIORITIES[selectedIssue.priority].label, icon: PRIORITIES[selectedIssue.priority].icon, color: PRIORITIES[selectedIssue.priority].color },
              ].map(s => (
                <div key={s.label} className="bg-white/5 rounded-xl p-3">
                  <p className="text-[10px] text-white/30 mb-1 uppercase tracking-wider">{s.label}</p>
                  <div className="flex items-center gap-1.5">
                    <i className={`ti ${s.icon} text-sm ${s.color}`} />
                    <span className={`font-semibold text-sm ${s.color}`}>{s.value}</span>
                  </div>
                </div>
              ))}
            </div>
            <div className="flex flex-wrap gap-1.5 mb-5">
              {selectedIssue.labels.map(l => (
                <span key={l} className={`text-xs font-semibold px-2 py-1 rounded-lg ${LABEL_COLORS[l] ?? "bg-white/10 text-white/40"}`}>{l}</span>
              ))}
            </div>
            <div className="border-t border-white/5 pt-4 flex gap-2">
              <button className="flex-1 py-2 text-sm bg-cl-accent text-navy font-bold rounded-lg hover:bg-cl-accent/90 transition-all">
                <i className="ti ti-pencil mr-1" /> Editar issue
              </button>
              <button className="py-2 px-4 text-sm text-white/60 bg-white/5 hover:bg-white/10 rounded-lg transition-all">
                <i className="ti ti-player-play" />
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

