import { useState } from "react";

type ERPTab = "cotizaciones" | "facturas" | "compras" | "inventario";

type QuoteStatus = "borrador" | "enviada" | "aceptada" | "rechazada" | "vencida";
type InvoiceStatus = "pendiente" | "pagada" | "vencida" | "cancelada";
