  id: string;
  bank: string;
  alias: string;
  cbu: string;
  currency: "ARS" | "USD";
  balance: number;
  color: string;
  icon: string;
  lastUpdate: string;
  type: "corriente" | "caja_ahorro" | "virtual";
};

type Transaction = {
  id: string;
  date: string;
  description: string;
  category: string;
  account: string;
  amount: number;
  type: "ingreso" | "egreso";
  status: "confirmado" | "pendiente" | "rechazado";
  reference: string;
};

