import { useState, useEffect } from "react";
import { useAuth } from "@workspace/replit-auth-web";

interface AdminUser {
  id: string;
  email: string | null;
  firstName: string | null;
  lastName: string | null;
  createdAt: string;
  plan: string;
  status: string;
  currentPeriodEnd: string | null;
  mpPaymentId: string | null;
}

const PLANS = ["free", "starter", "pro", "business", "enterprise"] as const;
type PlanKey = typeof PLANS[number];

const PLAN_META: Record<string, { label: string; accent: string; bg: string }> = {
  free:       { label: "Free",       accent: "#6b7280", bg: "bg-white/5" },
  starter:    { label: "Starter",    accent: "#1056f3", bg: "bg-cl-blue/10" },
  pro:        { label: "Pro",        accent: "#2dd8a0", bg: "bg-cl-accent/10" },
  business:   { label: "Business",  accent: "#f59e0b", bg: "bg-yellow-400/10" },
  enterprise: { label: "Enterprise", accent: "#a855f7", bg: "bg-purple-400/10" },
  none:       { label: "Sin plan",   accent: "#4b5563", bg: "bg-white/5" },
  trialing:   { label: "Prueba",     accent: "#f59e0b", bg: "bg-yellow-400/10" },
};

function formatDate(d: string | null) {
  if (!d) return "—";
  const date = new Date(d);
  if (date.getFullYear() > 2100) return "Sin vencimiento";
  return date.toLocaleDateString("es-AR", { day: "numeric", month: "short", year: "numeric" });
}

function PlanBadge({ plan, status }: { plan: string; status: string }) {
  const key = status === "trialing" ? "trialing" : plan;
  const m = PLAN_META[key] ?? PLAN_META.none;
  return (
    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-[11px] font-bold ${m.bg}`}
      style={{ color: m.accent }}>
      {m.label}
    </span>
  );
}

function StatusDot({ status }: { status: string }) {
  if (status === "active") return <span className="flex items-center gap-1.5 text-cl-accent text-xs font-semibold"><span className="w-1.5 h-1.5 rounded-full bg-cl-accent animate-pulse inline-block" />Activo</span>;
  if (status === "trialing") return <span className="flex items-center gap-1.5 text-yellow-400 text-xs font-semibold"><span className="w-1.5 h-1.5 rounded-full bg-yellow-400 animate-pulse inline-block" />Prueba</span>;
  return <span className="text-white/30 text-xs">{status === "none" ? "Sin suscripción" : status}</span>;
}

export default function AdminPage() {
  const { user, isLoading } = useAuth();
  const [users, setUsers] = useState<AdminUser[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [filterPlan, setFilterPlan] = useState("all");
  const [updatingId, setUpdatingId] = useState<string | null>(null);
  const [tab, setTab] = useState<"users" | "system">("users");

  const isAdmin = !isLoading && user?.email?.endsWith("@clientum.com.ar") && user.email !== "demo@clientum.com.ar";

  const load = () => {
    setLoading(true);
    fetch("/api/admin/users", { credentials: "include" })
      .then(r => r.json())
      .then((d: { users: AdminUser[]; total: number }) => {
        setUsers(d.users ?? []);
        setTotal(d.total ?? 0);
        setLoading(false);
      })
      .catch(() => setLoading(false));
  };

  useEffect(() => { if (isAdmin) load(); }, [isAdmin]);

  const handlePlanChange = async (userId: string, plan: string) => {
    setUpdatingId(userId);
    await fetch(`/api/admin/users/${userId}/plan`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify({ plan, status: "active" }),
    });
    setUsers(prev => prev.map(u => u.id === userId ? { ...u, plan, status: "active" } : u));
    setUpdatingId(null);
  };

  if (isLoading) {
    return (
      <div className="flex-1 flex items-center justify-center">
        <div className="w-10 h-10 border-4 border-cl-accent border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  if (!isAdmin) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center gap-4 p-8">
        <div className="w-16 h-16 rounded-2xl bg-red-400/10 flex items-center justify-center">
          <i className="ti ti-shield-lock text-3xl text-red-400" />
        </div>
        <div className="text-center">
          <h2 className="text-white font-bold text-lg">Acceso restringido</h2>
          <p className="text-white/50 text-sm mt-1">Esta sección es solo para administradores de Clientum.</p>
        </div>
      </div>
    );
  }

  const filtered = users.filter(u => {
    const q = search.toLowerCase();
    const matchSearch = !q
      || (u.email ?? "").toLowerCase().includes(q)
      || (u.firstName ?? "").toLowerCase().includes(q)
      || (u.lastName ?? "").toLowerCase().includes(q);
    const matchPlan = filterPlan === "all"
      || (filterPlan === "trialing" ? u.status === "trialing" : u.plan === filterPlan);
    return matchSearch && matchPlan;
  });

  const stats = [
    { label: "Total usuarios",  value: total,                                                             icon: "ti-users",           accent: "#1056f3" },
    { label: "Enterprise / Biz", value: users.filter(u => u.plan === "enterprise" || u.plan === "business").length, icon: "ti-crown",    accent: "#a855f7" },
    { label: "Pro",              value: users.filter(u => u.plan === "pro").length,                        icon: "ti-star",            accent: "#2dd8a0" },
    { label: "En prueba",        value: users.filter(u => u.status === "trialing").length,                 icon: "ti-clock",           accent: "#f59e0b" },
    { label: "Starter",          value: users.filter(u => u.plan === "starter").length,                    icon: "ti-bolt",            accent: "#3b82f6" },
    { label: "Free / Sin plan",  value: users.filter(u => !u.plan || u.plan === "free" || u.plan === "none").length, icon: "ti-lock-open", accent: "#6b7280" },
  ];

  const TABS = [
    { id: "users",  label: "Usuarios",    icon: "ti-users" },
    { id: "system", label: "Sistema",     icon: "ti-server" },
  ] as const;

  return (
    <div className="p-6 max-w-7xl mx-auto space-y-6">

      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-purple-400/10 flex items-center justify-center">
            <i className="ti ti-shield-lock text-xl text-purple-400" />
          </div>
          <div>
            <h2 className="text-white font-bold text-lg">Panel de Administración</h2>
            <p className="text-white/40 text-xs">Solo visible para cuentas @clientum.com.ar</p>
          </div>
        </div>
        <button onClick={load} disabled={loading}
          className="flex items-center gap-2 px-4 py-2 bg-navy-2 border border-white/10 rounded-lg text-xs font-semibold text-white/60 hover:text-white hover:border-white/25 transition-all disabled:opacity-50">
          <i className={`ti ti-refresh text-sm ${loading ? "animate-spin" : ""}`} />
          Actualizar
        </button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 md:grid-cols-3 xl:grid-cols-6 gap-3">
        {stats.map(s => (
          <div key={s.label} className="bg-navy-2 border border-white/10 rounded-xl p-4">
            <div className="w-8 h-8 rounded-lg flex items-center justify-center mb-2" style={{ background: `${s.accent}20` }}>
              <i className={`ti ${s.icon} text-base`} style={{ color: s.accent }} />
            </div>
            <div className="text-2xl font-extrabold text-white">{loading ? "—" : s.value}</div>
            <div className="text-white/40 text-[11px] mt-0.5 leading-tight">{s.label}</div>
          </div>
        ))}
      </div>

      {/* Tabs */}
      <div className="flex gap-1 bg-navy-2 border border-white/10 rounded-xl p-1 w-fit">
        {TABS.map(t => (
          <button key={t.id} onClick={() => setTab(t.id)}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg text-xs font-bold transition-all ${
              tab === t.id ? "bg-cl-accent/10 text-cl-accent" : "text-white/50 hover:text-white"
            }`}>
            <i className={`ti ${t.icon} text-sm`} /> {t.label}
          </button>
        ))}
      </div>

      {/* Tab: Usuarios */}
      {tab === "users" && (
        <div className="bg-navy-2 border border-white/10 rounded-xl overflow-hidden">
          {/* Filters */}
          <div className="p-4 border-b border-white/5 flex flex-col sm:flex-row gap-3">
            <div className="relative flex-1">
              <i className="ti ti-search absolute left-3 top-1/2 -translate-y-1/2 text-white/30 text-sm" />
              <input type="text" placeholder="Buscar por email o nombre..."
                value={search} onChange={e => setSearch(e.target.value)}
                className="w-full bg-navy border border-white/10 rounded-lg pl-9 pr-4 py-2.5 text-sm text-white placeholder:text-white/25 focus:outline-none focus:border-cl-accent/50 transition-colors" />
            </div>
            <select value={filterPlan} onChange={e => setFilterPlan(e.target.value)}
              className="bg-navy border border-white/10 rounded-lg px-3 py-2.5 text-sm text-white focus:outline-none focus:border-cl-accent/50 transition-colors">
              <option value="all">Todos los planes</option>
              <option value="enterprise">Enterprise</option>
              <option value="business">Business</option>
              <option value="pro">Pro</option>
              <option value="starter">Starter</option>
              <option value="free">Free</option>
              <option value="none">Sin plan</option>
              <option value="trialing">⏳ En prueba</option>
            </select>
          </div>

          {/* Table */}
          {loading ? (
            <div className="p-12 flex flex-col items-center gap-3">
              <div className="w-8 h-8 border-2 border-cl-accent border-t-transparent rounded-full animate-spin" />
              <p className="text-white/40 text-sm">Cargando usuarios...</p>
            </div>
          ) : filtered.length === 0 ? (
            <div className="p-12 text-center">
              <i className="ti ti-search-off text-3xl text-white/20 block mb-2" />
              <p className="text-white/40 text-sm">No se encontraron usuarios.</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead>
                  <tr className="border-b border-white/5">
                    {["Usuario", "Plan", "Estado", "Vencimiento", "Registro", "MP Payment ID", "Cambiar plan"].map(h => (
                      <th key={h} className="px-5 py-3 text-left text-[10px] font-bold uppercase tracking-widest text-white/25">{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/[0.04]">
                  {filtered.map(u => {
                    const name = [u.firstName, u.lastName].filter(Boolean).join(" ") || "—";
                    return (
                      <tr key={u.id} className="hover:bg-white/[0.02] transition-colors group">
                        <td className="px-5 py-3">
                          <div className="flex items-center gap-2.5">
                            <div className="w-7 h-7 rounded-full bg-cl-accent/10 flex items-center justify-center text-cl-accent text-xs font-bold flex-shrink-0">
                              {name !== "—" ? name.charAt(0).toUpperCase() : "?"}
                            </div>
                            <div className="min-w-0">
                              <p className="text-white font-semibold text-xs truncate">{name}</p>
                              <p className="text-white/40 text-[11px] truncate">{u.email ?? "Sin email"}</p>
                            </div>
                          </div>
                        </td>
                        <td className="px-5 py-3">
                          <PlanBadge plan={u.plan} status={u.status} />
                        </td>
                        <td className="px-5 py-3">
                          <StatusDot status={u.status} />
                        </td>
                        <td className="px-5 py-3 text-white/50 text-xs">{formatDate(u.currentPeriodEnd)}</td>
                        <td className="px-5 py-3 text-white/40 text-xs">{formatDate(u.createdAt)}</td>
                        <td className="px-5 py-3 text-white/30 text-[11px] font-mono">{u.mpPaymentId ?? "—"}</td>
                        <td className="px-5 py-3">
                          <div className="flex items-center gap-2">
                            <select value={u.plan} disabled={updatingId === u.id}
                              onChange={e => void handlePlanChange(u.id, e.target.value)}
                              className="bg-navy border border-white/10 rounded-lg px-2 py-1.5 text-xs text-white focus:outline-none focus:border-cl-accent/50 disabled:opacity-50 transition-colors">
                              {PLANS.map(p => (
                                <option key={p} value={p}>{p.charAt(0).toUpperCase() + p.slice(1)}</option>
                              ))}
                            </select>
                            {updatingId === u.id && (
                              <div className="w-3.5 h-3.5 border-2 border-cl-accent border-t-transparent rounded-full animate-spin flex-shrink-0" />
                            )}
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}

          {/* Footer */}
          <div className="px-5 py-3 border-t border-white/5 flex items-center justify-between">
            <p className="text-white/30 text-xs">Mostrando {filtered.length} de {total} usuarios</p>
            <p className="text-white/20 text-[11px] font-mono">{user?.id}</p>
          </div>
        </div>
      )}

      {/* Tab: Sistema */}
      {tab === "system" && (
        <div className="space-y-4">
          {/* Info de entorno */}
          <div className="bg-navy-2 border border-white/10 rounded-xl p-5">
            <h3 className="text-white font-bold text-sm mb-4 flex items-center gap-2">
              <i className="ti ti-server text-cl-accent" /> Entorno
            </h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              {[
                { label: "Admin ID",       value: user?.id ?? "—" },
                { label: "Admin email",    value: user?.email ?? "—" },
                { label: "NODE_ENV",       value: import.meta.env.MODE },
                { label: "Base URL",       value: import.meta.env.BASE_URL },
                { label: "DEV mode",       value: import.meta.env.DEV ? "Sí" : "No" },
                { label: "Fecha/hora",     value: new Date().toLocaleString("es-AR") },
              ].map(row => (
                <div key={row.label} className="flex items-center justify-between gap-4 px-4 py-2.5 bg-navy rounded-lg border border-white/5">
                  <span className="text-white/40 text-xs">{row.label}</span>
                  <span className="text-white/80 text-xs font-mono truncate max-w-[200px]">{row.value}</span>
                </div>
              ))}
            </div>
          </div>

          {/* Endpoints de utilidad */}
          <div className="bg-navy-2 border border-white/10 rounded-xl p-5">
            <h3 className="text-white font-bold text-sm mb-4 flex items-center gap-2">
              <i className="ti ti-tool text-cl-accent" /> Herramientas rápidas
            </h3>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              {[
                { label: "Dev Login (solo dev)",    href: "/api/auth/dev-login",    icon: "ti-login",        note: "Solo funciona en NODE_ENV=development" },
                { label: "Estado de auth",          href: "/api/auth/user",          icon: "ti-user-check",   note: "Retorna el usuario de sesión actual" },
                { label: "Settings de cuenta",      href: "/api/settings",           icon: "ti-settings",     note: "Plan, features y datos del usuario" },
                { label: "Lista de usuarios (API)", href: "/api/admin/users",         icon: "ti-users",        note: "JSON con todos los usuarios y planes" },
                { label: "Historial de pagos",      href: "/api/payments/history",   icon: "ti-receipt",      note: "Eventos de MercadoPago del usuario" },
                { label: "Status chatbot",          href: "/api/chatbot/status",     icon: "ti-robot",        note: "Configuración y estado del bot" },
              ].map(tool => (
                <a key={tool.label} href={tool.href} target="_blank" rel="noreferrer"
                  className="flex items-start gap-3 px-4 py-3 bg-navy rounded-lg border border-white/5 hover:border-cl-accent/30 hover:bg-cl-accent/5 transition-all group">
                  <i className={`ti ${tool.icon} text-base text-white/40 group-hover:text-cl-accent transition-colors mt-0.5 flex-shrink-0`} />
                  <div className="min-w-0">
                    <p className="text-white/80 text-xs font-semibold group-hover:text-white transition-colors">{tool.label}</p>
                    <p className="text-white/30 text-[11px] mt-0.5">{tool.note}</p>
                    <p className="text-cl-accent/60 text-[11px] font-mono mt-0.5">{tool.href}</p>
                  </div>
                  <i className="ti ti-external-link text-white/20 group-hover:text-cl-accent/60 transition-colors flex-shrink-0 ml-auto text-xs mt-0.5" />
                </a>
              ))}
            </div>
          </div>

          {/* Acciones de mantenimiento */}
          <div className="bg-navy-2 border border-white/10 rounded-xl p-5">
            <h3 className="text-white font-bold text-sm mb-4 flex items-center gap-2">
              <i className="ti ti-alert-triangle text-yellow-400" /> Acciones de mantenimiento
            </h3>
            <div className="space-y-3">
              <div className="flex items-center justify-between gap-4 px-4 py-3 bg-navy rounded-lg border border-white/5">
                <div>
                  <p className="text-white/80 text-xs font-semibold">Cerrar sesión global</p>
                  <p className="text-white/30 text-[11px] mt-0.5">Cierra la sesión actual y redirige al login</p>
                </div>
                <a href="/api/auth/logout"
                  className="flex-shrink-0 flex items-center gap-1.5 px-3 py-1.5 bg-red-400/10 border border-red-400/20 rounded-lg text-red-400 text-xs font-bold hover:bg-red-400/20 transition-colors">
                  <i className="ti ti-logout text-sm" /> Logout
                </a>
              </div>
              <div className="flex items-center justify-between gap-4 px-4 py-3 bg-navy rounded-lg border border-white/5">
                <div>
                  <p className="text-white/80 text-xs font-semibold">Recrear usuario admin</p>
                  <p className="text-white/30 text-[11px] mt-0.5">Comando: <span className="font-mono text-white/50">pnpm --filter @workspace/scripts run seed:admin</span></p>
                </div>
                <span className="flex-shrink-0 flex items-center gap-1.5 px-3 py-1.5 bg-white/5 rounded-lg text-white/30 text-xs">
                  <i className="ti ti-terminal text-sm" /> CLI
                </span>
              </div>
              <div className="flex items-center justify-between gap-4 px-4 py-3 bg-navy rounded-lg border border-white/5">
                <div>
                  <p className="text-white/80 text-xs font-semibold">Aplicar migraciones de DB</p>
                  <p className="text-white/30 text-[11px] mt-0.5">Comando: <span className="font-mono text-white/50">pnpm --filter @workspace/db run push</span></p>
                </div>
                <span className="flex-shrink-0 flex items-center gap-1.5 px-3 py-1.5 bg-white/5 rounded-lg text-white/30 text-xs">
                  <i className="ti ti-terminal text-sm" /> CLI
                </span>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

